BoxedPrimitiveEquality.checker_dsl:
EXISTS (`binary expression BE`) {
  AND {
    (`BE is a binary expression with operator == or !=`),
    EXISTS (`left operand LO`) {
      AND {
        (`LO is the left operand of BE`),
        (`LO is not a null literal`),
        EXISTS (`type T1`) {
          AND {
            (`T1 is the type of LO`),
            (`T1 is not null`),
            (`T1 is not a primitive type`),
            EXISTS (`type U1`) {
              AND {
                (`U1 is the unboxed type of T1`),
                (`U1 is a primitive type`)
              }
            }
          }
        }
      }
    },
    EXISTS (`right operand RO`) {
      AND {
        (`RO is the right operand of BE`),
        (`RO is not a null literal`),
        EXISTS (`type T2`) {
          AND {
            (`T2 is the type of RO`),
            (`T2 is not null`),
            (`T2 is not a primitive type`),
            EXISTS (`type U2`) {
              AND {
                (`U2 is the unboxed type of T2`),
                (`U2 is a primitive type`)
              }
            }
          }
        }
      }
    }
  }
}

