NarrowingCompoundAssignment.checker_dsl:
EXISTS (`compound assignment CA`) {
  AND {
    (`the type of CA's left-hand side variable is a primitive type`),
    (`the type of CA's right-hand side expression is NOT convertible to the type of CA's left-hand side variable`),
    NOT {
      OR {
        (`CA's operator is RIGHT_SHIFT_ASSIGNMENT (>>=)`),
        AND {
          (`CA's operator is one of: AND_ASSIGNMENT (&=), XOR_ASSIGNMENT (^=), OR_ASSIGNMENT (|=)`),
          EXISTS (`constant value CV`) {
            AND {
              (`CV is the compile-time constant value of CA's right-hand side expression`),
              (`CV is an instance of Integer or Long`),
              OR {
                AND {
                  (`the type of CA's left-hand side variable is BYTE`),
                  OR {
                    (`(CV shifted right by 8 bits) equals 0`),
                    (`(CV shifted right by 8 bits) equals ~0 (all bits set)`)
                  }
                },
                AND {
                  (`the type of CA's left-hand side variable is SHORT`),
                  OR {
                    (`(CV shifted right by 16 bits) equals 0`),
                    (`(CV shifted right by 16 bits) equals ~0 (all bits set)`)
                  }
                }
              }
            }
          }
        }
      }
    }
  }
}

